import type { ComponentProps } from 'react';
import { CheckboxGroup as CheckboxGroupPrimitive } from '@base-ui/react/checkbox-group';
import { clsx } from 'clsx';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import { Checkbox, CheckboxField, CheckboxLabel } from '../checkbox';
import styles from './CheckboxGroup.module.css';

function CheckboxGroup({ className, ...props }: CheckboxGroupPrimitive.Props) {
  return (
    <CheckboxGroupPrimitive
      data-slot="checkbox-group-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
}

function CheckboxGroupLabel({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="checkbox-group-label" className={clsx(styles.label, className)} {...props} />
  );
}

function CheckboxGroupList({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="checkbox-group-list" className={clsx(styles.list, className)} {...props} />
  );
}

function CheckboxGroupItem({ className, ...props }: ComponentProps<typeof CheckboxField>) {
  return (
    <CheckboxField
      data-slot="checkbox-group-item"
      className={clsx(styles.item, className)}
      {...props}
    />
  );
}

function CheckboxGroupItemControl(props: ComponentProps<typeof Checkbox>) {
  return <Checkbox data-slot="checkbox-group-item-control" {...props} />;
}

function CheckboxGroupItemLabel({ className, ...props }: ComponentProps<typeof CheckboxLabel>) {
  return (
    <CheckboxLabel
      data-slot="checkbox-group-item-label"
      className={clsx(styles.itemLabel, className)}
      {...props}
    />
  );
}

export {
  CheckboxGroup,
  CheckboxGroupLabel,
  CheckboxGroupList,
  CheckboxGroupItem,
  CheckboxGroupItemControl,
  CheckboxGroupItemLabel,
};

@layer ui.components {
  .root {
    display: flex;
    flex-direction: column;
    gap: var(--checkbox-group-gap, var(--spacing-2));
    color: var(--checkbox-group-color, var(--color-foreground));
  }

  .label {
    color: var(--checkbox-group-label-color, var(--checkbox-group-color, var(--color-foreground)));
    font-size: var(--checkbox-group-label-font-size, var(--text-sm));
    font-weight: var(--checkbox-group-label-font-weight, var(--weight-semibold));
    line-height: var(--checkbox-group-label-line-height, var(--line-height-text-sm));
  }

  .list {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--checkbox-group-list-gap, var(--spacing-2));
  }

  .item {
    gap: var(--checkbox-group-item-gap, var(--checkbox-gap, var(--spacing-2)));
  }

  .itemLabel {
    color: var(
      --checkbox-group-item-label-color,
      var(--checkbox-label-color, var(--color-foreground))
    );
    font-size: var(
      --checkbox-group-item-label-font-size,
      var(--checkbox-label-font-size, var(--text-sm))
    );
    font-weight: var(
      --checkbox-group-item-label-font-weight,
      var(--checkbox-label-font-weight, var(--weight-medium))
    );
    line-height: var(
      --checkbox-group-item-label-line-height,
      var(--checkbox-label-line-height, var(--line-height-text-sm))
    );
  }
}

export {
  CheckboxGroup,
  CheckboxGroupLabel,
  CheckboxGroupList,
  CheckboxGroupItem,
  CheckboxGroupItemControl,
  CheckboxGroupItemLabel,
} from './CheckboxGroup';
